// Returns the elements of `items` for which `predicate` returns true.
function pickWhere(items: any[], predicate: (item: any) => boolean): any[] {
  const out: any[] = [];
  for (const item of items) {
    if (predicate(item)) out.push(item);
  }
  return out;
}

